public static long[] solve(String[] words) {
    int n = words.length;
    if (n == 0) return new long[0];
    if (n == 1) return new long[] {0};

    int[] lcp = new int[n - 1];
    for (int i = 0; i < n - 1; i++) {
        lcp[i] = computeLCP(words[i], words[i + 1]);
    }

    int[] prefixMax = new int[n - 1];
    prefixMax[0] = lcp[0];
    for (int i = 1; i < n - 1; i++) {
        prefixMax[i] = Math.max(prefixMax[i - 1], lcp[i]);
    }

    int[] suffixMax = new int[n - 1];
    suffixMax[n - 2] = lcp[n - 2];
    for (int i = n - 3; i >= 0; i--) {
        suffixMax[i] = Math.max(lcp[i], suffixMax[i + 1]);
    }

    long[] answer = new long[n];
    for (int i = 0; i < n; i++) {
        long leftMax = 0;
        if (i - 2 >= 0) {
            leftMax = prefixMax[i - 2];
        }
        long rightMax = 0;
        if (i + 1 <= n - 2) {
            rightMax = suffixMax[i + 1];
        }
        long newPair = 0;
        if (i - 1 >= 0 && i + 1 < n) {
            newPair = computeLCP(words[i - 1], words[i + 1]);
        }
        answer[i] = Math.max(Math.max(leftMax, rightMax), newPair);
    }

    return answer;
}

private static int computeLCP(String a, String b) {
    int len = 0;
    while (len < a.length() && len < b.length() && a.charAt(len) == b.charAt(len)) {
        len++;
    }
    return len;
}
